{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_01MKHq27tAYiMoohTbyckcRu","type":"tool_result","content":"     1→//
     2→//  RightSidebarPanel.swift
     3→//  unbound-macos
     4→//
     5→//  Right panel with git operations: branch selector, commit/push actions,
     6→//  and Changes/Files/Commits tabs.
     7→//
     8→
     9→import Logging
    10→import OpenTelemetryApi
    11→import SwiftUI
    12→
    13→private let logger = Logger(label: "app.ui.sidebar")
    14→
    15→struct RightSidebarPanel: View {
    16→    @Environment(\.colorScheme) private var colorScheme
    17→    @Environment(\.scenePhase) private var scenePhase
    18→    @Environment(AppState.self) private var appState
    19→
    20→    // View models
    21→    var fileTreeViewModel: FileTreeViewModel?
    22→    @Bindable var gitViewModel: GitViewModel
    23→    @Bindable var editorState: EditorState
    24→
    25→    // State bindings
    26→    @Binding var selectedTab: RightSidebarTab
    27→
    28→    // Working directory
    29→    let workingDirectory: String?
    30→    var onOpenEditorTab: ((UUID) -> Void)? = nil
    31→
    32→    // Header action state
    33→    @State private var isCommitDropdownOpen = false
    34→    @State private var isPushDropdownOpen = false
    35→    @State private var hoveredDropdownItem: String?
    36→    @State private var isDispatchingAgentAction = false
    37→
    38→    private enum HeaderPrimaryActionMode: Equatable {
    39→        case commit
    40→        case push
    41→        case disabledCommit
    42→    }
    43→
    44→    private var colors: ThemeColors {
    45→        ThemeColors(colorScheme)
    46→    }
    47→
    48→    private var effectiveTab: RightSidebarTab {
    49→        selectedTab == .spec ? .changes : selectedTab
    50→    }
    51→
    52→    private var bottomTabs: [RightSidebarTab] {
    53→        [.changes, .files, .commits]
    54→    }
    55→
    56→    private var selectedSessionLiveState: SessionLiveState? {
    57→        guard let session = appState.selectedSession else { return nil }
    58→        return appState.sessionStateManager.stateIfExists(for: session.id)
    59→    }
    60→
    61→    private var isSelectedSessionStreaming: Bool {
    62→        selectedSessionLiveState?.codingSessionStatus.isStreaming ?? false
    63→    }
    64→
    65→    private var canDispatchGitAgentAction: Bool {
    66→        guard appState.selectedSession != nil else { return false }
    67→        guard let workingDirectory, !workingDirectory.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
    68→            return false
    69→        }
    70→        return !isDispatchingAgentAction && !gitViewModel.isPerformingAction && !isSelectedSessionStreaming
    71→    }
    72→
    73→    private var headerPrimaryActionMode: HeaderPrimaryActionMode {
    74→        if gitViewModel.hasUncommittedChanges {
    75→            return .commit
    76→        }
    77→        if gitViewModel.hasUnpushedCommits {
    78→            return .push
    79→        }
    80→        return .disabledCommit
    81→    }
    82→
    83→    var body: some View {
    84→        VStack(spacing: 0) {
    85→            sidebarHeader
    86→            ShadcnDivider()
    87→            errorBanner
    88→            bottomTabHeader
    89→            ShadcnDivider()
    90→            bottomTabContent
    91→        }
    92→        .background(colors.background)
    93→        .onChange(of: selectedTab) { _, newTab in
    94→            if newTab == .files {
    95→                Task { await fileTreeViewModel?.loadRoot() }
    96→            }
    97→        }
    98→        .onChange(of: headerPrimaryActionMode) { _, _ in
    99→            isCommitDropdownOpen = false
   100→            isPushDropdownOpen = false
   101→        }
   102→        .onChange(of: scenePhase) { oldPhase, newPhase in
   103→            guard oldPhase != .active, newPhase == .active else { return }
   104→            Task {
   105→                await refreshSidebarOnAppReactivationIfNeeded()
   106→            }
   107→        }
   108→        .onChange(of: isSelectedSessionStreaming) { wasStreaming, isStreaming in
   109→            guard wasStreaming && !isStreaming else { return }
   110→            Task { await gitViewModel.refreshAll() }
   111→        }
   112→        .onChange(of: workingDirectory) { _, newPath in
   113→            Task {
   114→                await gitViewModel.setRepository(path: newPath)
   115→            }
   116→        }
   117→        .onAppear {
   118→            Task { @MainActor in
   119→                gitViewModel.setDaemonClient(appState.daemonClient)
   120→                if selectedTab == .spec {
   121→                    selectedTab = .changes
   122→                }
   123→                await gitViewModel.setRepository(path: workingDirectory)
   124→                if selectedTab == .files {
   125→                    await fileTreeViewModel?.loadRoot()
   126→                }
   127→            }
   128→        }
   129→    }
   130→
   131→    private func refreshSidebarOnAppReactivationIfNeeded() async {
   132→        guard let workingDirectory,
   133→              !workingDirectory.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
   134→            return
   135→        }
   136→        guard appState.isDaemonConnected else { return }
   137→
   138→        let tab = effectiveTab
   139→        guard gitViewModel.canRefreshSidebarData(for: tab) else { return }
   140→
   141→        await gitViewModel.refreshSidebarData(for: tab)
   142→    }
