   189→    // MARK: - Header Actions
   190→
   191→    private var isGHAuthenticated: Bool {
   192→        guard let auth = gitViewModel.ghAuthStatus else { return false }
   193→        return auth.authenticatedHostCount > 0
   194→    }
   195→
   196→    private var isCommitDisabled: Bool {
   197→        !gitViewModel.hasUncommittedChanges || !canDispatchGitAgentAction
   198→    }
   199→
   200→    private var isPushDisabled: Bool {
   201→        !gitViewModel.hasUnpushedCommits || !canDispatchGitAgentAction
   202→    }
