   434→    private func dispatchGitAgentAction(_ action: GitSidebarAgentAction) {
   435→        guard !isDispatchingAgentAction else { return }
   436→        guard let session = appState.selectedSession else {
   437→            gitViewModel.lastError = "Select a coding session before running Git actions."
   438→            return
   439→        }
   440→        guard let workspacePath = workingDirectory,
   441→              !workspacePath.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
   442→            gitViewModel.lastError = "Open a repository workspace before running Git actions."
   443→            return
   444→        }
   445→        guard canDispatchGitAgentAction else {
   446→            gitViewModel.lastError = "Git actions are unavailable while the session agent is busy."
   447→            return
   448→        }
   449→
   450→        let liveState = appState.sessionStateManager.state(for: session.id)
   451→        let prompt = GitAgentPromptFactory.prompt(for: action)
   452→
   453→        isDispatchingAgentAction = true
   454→        gitViewModel.lastError = nil
   455→
   456→        Task { @MainActor in
   457→            await liveState.sendMessage(
   458→                prompt,
   459→                session: session,
   460→                workspacePath: workspacePath,
   461→                modelIdentifier: nil,
   462→                isPlanMode: false
   463→            )
   464→
   465→            if liveState.showErrorAlert {
   466→                let message = liveState.errorAlertMessage.trimmingCharacters(in: .whitespacesAndNewlines)
   467→                if !message.isEmpty {
   468→                    gitViewModel.lastError = message
   469→                }
   470→            }
   471→
   472→            isDispatchingAgentAction = false
   473→        }
   474→    }
