   589→    // MARK: - Actions
   590→
   591→    private func selectFile(_ file: GitStatusFile) {
   592→        gitViewModel.selectFile(file.path)
   593→        let tabId = editorState.openDiffTab(relativePath: file.path)
   594→        onOpenEditorTab?(tabId)
   595→        Task {
   596→            await loadDiffForFile(file.path)
   597→        }
   598→    }
   599→
   600→    private func selectFile(_ file: FileItem) {
   601→        guard !file.isDirectory else { return }
   602→        fileTreeViewModel?.selectFile(file.path)
   603→        if let fullPath = resolveFullPath(for: file) {
   604→            let tabId = editorState.openFileTab(
   605→                relativePath: file.path,
   606→                fullPath: fullPath,
   607→                sessionId: appState.selectedSessionId
   608→            )
   609→            onOpenEditorTab?(tabId)
   610→        }
   611→    }
   612→
   613→    private func resolveFullPath(for file: FileItem) -> String? {
   614→        if file.path.hasPrefix("/") {
   615→            return file.path
   616→        }
   617→        guard let workDir = workingDirectory else { return nil }
   618→        return URL(fileURLWithPath: workDir).appendingPathComponent(file.path).path
   619→    }
   620→
   621→    private func loadDiffForFile(_ path: String) async {
   622→        guard let workDir = workingDirectory else { return }
   623→
   624→        editorState.setDiffLoading(for: path, isLoading: true)
   625→        defer { editorState.setDiffLoading(for: path, isLoading: false) }
   626→
   627→        do {
   628→            try await TracingService.withUserIntentRootIfNeeded(
   629→                name: "git.diff_file",
   630→                attributes: [
   631→                    "repository.path_hash": .string(TracingService.hashIdentifier(workDir) ?? ""),
   632→                    "repository.relative_path_hash": .string(TracingService.hashIdentifier(path) ?? "")
   633→                ]
   634→            ) { _ in
   635→                let diffContent = try await appState.daemonClient.getGitDiff(path: workDir, filePath: path)
   636→                if !diffContent.isEmpty {
   637→                    editorState.setDiff(for: path, diff: FileDiff.parse(from: diffContent, filePath: path))
   638→                } else {
   639→                    editorState.setDiff(for: path, diff: nil)
   640→                }
   641→            }
   642→        } catch {
   643→            logger.warning("Failed to load diff: \(error.localizedDescription)")
   644→            editorState.setDiffError(for: path, message: error.localizedDescription)
   645→        }
   646→    }
   647→}
